 1→import { sprintPhases, type PhaseData } from './sprintTasks';
 2→import { automationPhases } from './automationTasks';
 3→
 4→export type TrackType = 'startup' | 'automation';
 5→
 6→export interface TrackMeta {
 7→  id: TrackType;
 8→  title: string;
 9→  subtitle: string;
10→  description: string;
11→  iconName: 'Rocket' | 'Zap';
12→  requiredPhase1Keys: string[];
13→  phase1ContentKeys: {
14→    problem: string;
15→    solution: string;
16→    customer: string;
17→    name: string;
18→    advantage: string;
19→    validation: string;
20→    metrics: string;
21→  };
22→}
23→
24→export const trackMeta: Record<TrackType, TrackMeta> = {
25→  startup: {
26→    id: 'startup',
27→    title: 'Startup Launch Track',
28→    subtitle: 'Go from idea to live MVP in one evening',
29→    description: 'Define your startup idea, build a prototype, pitch it, and take it to market.',
30→    iconName: 'Rocket',
31→    requiredPhase1Keys: ['p1_problem', 'p1_solution', 'p1_customer'],
32→    phase1ContentKeys: {
33→      problem: 'p1_problem',
34→      solution: 'p1_solution',
35→      customer: 'p1_customer',
36→      name: 'p1_name',
37→      advantage: 'p1_advantage',
38→      validation: 'p1_validation',
39→      metrics: 'p1_metrics',
40→    },
41→  },
42→  automation: {
43→    id: 'automation',
44→    title: 'Automation & Innovation Track',
45→    subtitle: 'Build a workflow, tool, or automation that solves a real problem tonight',
46→    description: 'Identify a broken process, automate it, demo it, and get feedback.',
47→    iconName: 'Zap',
48→    requiredPhase1Keys: ['a1_workflow', 'a1_pain_points', 'a1_tools', 'a1_time_spent'],
49→    phase1ContentKeys: {
50→      problem: 'a1_workflow',
51→      solution: 'a1_ai_analysis',
52→      customer: 'a1_who_benefits',
53→      name: 'a1_name',
54→      advantage: '',
55→      validation: '',
56→      metrics: 'a1_success',
57→    },
58→  },
59→};
60→
61→export function getTrackPhases(track: TrackType): PhaseData[] {
62→  return track === 'automation' ? automationPhases : sprintPhases;
63→}
64→
65→export function getTrackMeta(track: TrackType): TrackMeta {
66→  return trackMeta[track];
67→}
