  1→import { useMemo, useState } from 'react';
  2→import { useNavigate, Navigate } from 'react-router-dom';
  3→import { useTeamAuth } from '@/contexts/TeamAuthContext';
  4→import { useSprintData } from '@/hooks/useSprintData';
  5→import { getTrackPhases, getTrackMeta, trackMeta, type TrackType } from '@/data/trackConfig';
  6→import { PhaseProgress } from '@/components/sprint/PhaseProgress';
  7→import { PhaseChecklist } from '@/components/sprint/PhaseChecklist';
  8→import { SprintTimer } from '@/components/sprint/SprintTimer';
  9→import { Button } from '@/components/ui/button';
 10→import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from '@/components/ui/dialog';
 11→import { LogOut, Rocket, Zap, Settings, ArrowRightLeft } from 'lucide-react';
 12→import { toast } from 'sonner';
 13→import type { Phase1Data } from '@/hooks/useAIGeneration';
 14→
 15→export default function Dashboard() {
 16→  const { team, logout, setTrack } = useTeamAuth();
 17→  const navigate = useNavigate();
 18→  const [showSwitchDialog, setShowSwitchDialog] = useState(false);
 19→  const [switching, setSwitching] = useState(false);
 20→
 21→  const track = team?.track ?? 'startup';
 22→  const meta = getTrackMeta(track);
 23→  const phases = getTrackPhases(track);
 24→  const REQUIRED_PHASE1_TASKS = meta.requiredPhase1Keys;
 25→  const p1Keys = meta.phase1ContentKeys;
 26→
 27→  const { completedTasks, taskContents, loading, saveTaskContent } = useSprintData(team?.id);
 28→
 29→  const { phase1Data, phase1Complete, missingPhase1Tasks } = useMemo(() => {
 30→    const problem = taskContents.get(p1Keys.problem) || '';
 31→    const solution = taskContents.get(p1Keys.solution) || '';
 32→    const customer = taskContents.get(p1Keys.customer) || '';
 33→    const name = taskContents.get(p1Keys.name) || '';
 34→    const unfairAdvantage = p1Keys.advantage ? taskContents.get(p1Keys.advantage) || '' : '';
 35→    const problemValidation = p1Keys.validation ? taskContents.get(p1Keys.validation) || '' : '';
 36→    const successMetrics = p1Keys.metrics ? taskContents.get(p1Keys.metrics) || '' : '';
 37→
 38→    const data: Phase1Data = {
 39→      problem,
 40→      solution,
 41→      customer,
 42→      name,
 43→      unfairAdvantage,
 44→      problemValidation,
 45→      successMetrics,
 46→      // Automation-specific fields
 47→      workflow: taskContents.get('a1_workflow') || undefined,
 48→      painPoints: taskContents.get('a1_pain_points') || undefined,
 49→      toolsUsed: taskContents.get('a1_tools') || undefined,
 50→      timeSpent: taskContents.get('a1_time_spent') || undefined,
 51→      aiAnalysis: taskContents.get('a1_ai_analysis') || undefined,
 52→    };
 53→
 54→    const missing = REQUIRED_PHASE1_TASKS.filter(
 55→      key => !completedTasks.has(key)
 56→    );
 57→
 58→    return {
 59→      phase1Data: data,
 60→      phase1Complete: missing.length === 0,
 61→      missingPhase1Tasks: missing,
 62→    };
 63→  }, [completedTasks, taskContents, REQUIRED_PHASE1_TASKS, p1Keys]);
 64→
 65→  const handleSwitchTrack = async (newTrack: TrackType) => {
 66→    setSwitching(true);
 67→    try {
 68→      await setTrack(newTrack);
 69→      setShowSwitchDialog(false);
 70→      toast.success(`Switched to ${trackMeta[newTrack].title}`);
 71→    } catch {
 72→      toast.error('Failed to switch track');
 73→    } finally {
 74→      setSwitching(false);
 75→    }
 76→  };
 77→
 78→  const handleLogout = () => {
 79→    logout();
 80→    navigate('/login');
 81→    toast.success('Logged out successfully');
 82→  };
 83→
 84→  // Redirect to track selection if no track chosen (after hooks)
 85→  if (team && !team.track) {
 86→    return <Navigate to="/track-selection" replace />;
 87→  }
 88→
 89→  if (loading) {
 90→    return (
 91→      <div className="min-h-screen flex items-center justify-center bg-background">
 92→        <div className="text-center">
 93→          <div className="w-8 h-8 border-4 border-foreground border-t-transparent animate-spin mb-4 mx-auto" />
 94→          <p className="font-mono text-sm text-muted-foreground">LOADING...</p>
 95→        </div>
 96→      </div>
 97→    );
 98→  }
 99→
100→  if (!team) {
101→    return null;
102→  }
103→
104→  const getCurrentPhase = () => {
105→    for (const phase of phases) {
106→      const phaseCompleted = phase.tasks.every(t => completedTasks.has(t.key));
107→      if (!phaseCompleted) {
108→        return phase.phase;
109→      }
110→    }
111→    return 'completed';
112→  };
113→
114→  const currentPhase = getCurrentPhase();
115→  const TrackIcon = track === 'automation' ? Zap : Rocket;
116→
117→  return (
118→    <div className="min-h-screen bg-background">
119→      <header className="border-b-4 border-foreground p-4 flex justify-between items-center">
120→        <span className="text-2xl font-bold tracking-tight">[HABITAT]</span>
121→        <Button
122→          variant="ghost"
123→          onClick={handleLogout}
124→          className="font-bold uppercase gap-2"
125→        >
126→          <LogOut className="w-4 h-4" />
127→          Log Out
128→        </Button>
129→      </header>
130→
131→      <div className="border-b-4 border-foreground">
132→        <div className="container py-6 flex flex-col md:flex-row md:items-center justify-between gap-4">
133→          <div>
134→            <p className="font-mono text-sm text-muted-foreground mb-1">SPRINT DASHBOARD</p>
135→            <div className="flex items-center gap-3">
136→              <h1 className="text-3xl font-bold">{team.name}</h1>
137→              <div className="flex items-center gap-1.5 border-2 border-foreground px-2 py-1 text-xs font-bold font-mono uppercase cursor-pointer hover:bg-muted transition-colors" onClick={() => setShowSwitchDialog(true)} title="Switch track">
138→                <TrackIcon className="w-3.5 h-3.5" />
139→                {track === 'automation' ? 'Automation' : 'Startup'}
140→                <ArrowRightLeft className="w-3 h-3 ml-1 opacity-50" />
141→              </div>
142→            </div>
143→          </div>
144→          <div className="flex-shrink-0">
145→            <SprintTimer />
146→          </div>
147→        </div>
148→      </div>
149→
150→      <main className="container py-8">
151→        <div className="mb-8">
152→          <PhaseProgress currentPhase={currentPhase} phases={phases} />
153→        </div>
154→
155→        {currentPhase === 'completed' && (
156→          <div className="border-4 border-success bg-success/10 p-6 mb-8 text-center">
157→            <p className="font-bold text-xl mb-2">🎉 SPRINT COMPLETED!</p>
158→            <p className="font-mono text-sm text-muted-foreground">
159→              Congratulations! You&apos;ve finished all the tasks.
160→            </p>
161→          </div>
162→        )}
163→
164→        <div className="space-y-4">
165→          {phases.map((phaseData) => (
166→            <PhaseChecklist
167→              key={phaseData.phase}
168→              phase={phaseData.phase}
169→              label={phaseData.label}
170→              description={phaseData.description}
171→              tasks={phaseData.tasks}
172→              teamId={team.id}
173→              currentPhase={currentPhase}
174→              completedTasks={completedTasks}
175→              taskContents={taskContents}
176→              phase1Data={phase1Data}
177→              phase1Complete={phase1Complete}
178→              missingPhase1Tasks={missingPhase1Tasks}
179→              onTaskSave={saveTaskContent}
180→            />
181→          ))}
182→        </div>
183→
184→        <div className="mt-12 border-4 border-foreground p-6 bg-muted">
185→          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
186→            <div>
187→              <p className="font-mono text-sm text-muted-foreground">TEAM NAME</p>
188→              <p className="font-bold text-2xl">{team.name}</p>
189→            </div>
190→            <div className="text-right">
191→              <p className="font-mono text-sm text-muted-foreground">
192→                Share team credentials with teammates to sync progress
193→              </p>
194→            </div>
195→          </div>
196→        </div>
197→      </main>
198→
199→      {/* Switch Track Dialog */}
200→      <Dialog open={showSwitchDialog} onOpenChange={setShowSwitchDialog}>
201→        <DialogContent className="border-4 border-foreground max-w-md">
202→          <DialogHeader>
203→            <DialogTitle className="font-mono font-bold">SWITCH TRACK</DialogTitle>
204→            <DialogDescription className="font-mono text-sm">
205→              Your progress is saved per track. Switching won't delete anything.
206→            </DialogDescription>
207→          </DialogHeader>
208→          <div className="space-y-3 py-2">
209→            {(Object.values(trackMeta) as typeof trackMeta[TrackType][]).map((t) => {
210→              const isActive = t.id === track;
211→              const Icon = t.iconName === 'Zap' ? Zap : Rocket;
212→              return (
213→                <button
214→                  key={t.id}
215→                  disabled={isActive || switching}
216→                  onClick={() => handleSwitchTrack(t.id)}
217→                  className={`w-full text-left border-2 p-4 transition-colors ${
218→                    isActive
219→                      ? 'border-primary bg-primary/5 opacity-70 cursor-default'
220→                      : 'border-foreground hover:bg-muted cursor-pointer'
221→                  }`}
222→                >
223→                  <div className="flex items-center gap-3">
224→                    <Icon className="w-5 h-5 shrink-0" />
225→                    <div>
226→                      <p className="font-mono font-bold text-sm">{t.title}</p>
227→                      <p className="font-mono text-xs text-muted-foreground">{t.subtitle}</p>
228→                    </div>
229→                    {isActive && (
230→                      <span className="ml-auto font-mono text-xs text-primary font-bold">CURRENT</span>
231→                    )}
232→                  </div>
233→                </button>
234→              );
235→            })}
236→          </div>
237→          <DialogFooter>
238→            <Button variant="outline" onClick={() => setShowSwitchDialog(false)} className="border-2 border-foreground font-mono">
239→              Cancel
240→            </Button>
241→          </DialogFooter>
242→        </DialogContent>
243→      </Dialog>
244→    </div>
245→  );
246→}
