  1→import { useState } from 'react';
  2→import { useNavigate, Link } from 'react-router-dom';
  3→import { useTeamAuth } from '@/contexts/TeamAuthContext';
  4→import { Button } from '@/components/ui/button';
  5→import { Input } from '@/components/ui/input';
  6→import { Label } from '@/components/ui/label';
  7→import { toast } from 'sonner';
  8→
  9→export default function Login() {
 10→  const [teamName, setTeamName] = useState('');
 11→  const [password, setPassword] = useState('');
 12→  const [loading, setLoading] = useState(false);
 13→  const { loginTeam } = useTeamAuth();
 14→  const navigate = useNavigate();
 15→
 16→  const handleSubmit = async (e: React.FormEvent) => {
 17→    e.preventDefault();
 18→    setLoading(true);
 19→
 20→    const { error, team } = await loginTeam(teamName.trim(), password);
 21→
 22→    if (error) {
 23→      toast.error(error);
 24→      setLoading(false);
 25→    } else {
 26→      toast.success('Welcome back, team!');
 27→      navigate(team?.track ? '/dashboard' : '/track-selection', { replace: true });
 28→    }
 29→  };
 30→
 31→  return (
 32→    <div className="min-h-screen bg-background flex flex-col">
 33→      {/* Header */}
 34→      <header className="border-b-4 border-foreground p-4">
 35→        <span className="text-2xl font-bold tracking-tight">[HABITAT]</span>
 36→      </header>
 37→
 38→      {/* Main content */}
 39→      <main className="flex-1 flex items-center justify-center p-4">
 40→        <div className="w-full max-w-md">
 41→          <div className="border-4 border-foreground bg-card shadow-brutal p-8">
 42→            <h1 className="text-3xl font-bold mb-2">TEAM LOGIN</h1>
 43→            <p className="text-muted-foreground mb-8 font-mono text-sm">
 44→              Enter your team credentials to continue
 45→            </p>
 46→
 47→            <form onSubmit={handleSubmit} className="space-y-6">
 48→              <div className="space-y-2">
 49→                <Label htmlFor="teamName" className="font-bold uppercase text-sm">
 50→                  Team Name
 51→                </Label>
 52→                <Input
 53→                  id="teamName"
 54→                  type="text"
 55→                  value={teamName}
 56→                  onChange={(e) => setTeamName(e.target.value)}
 57→                  placeholder="Your team name"
 58→                  required
 59→                  className="border-2 border-foreground h-12 font-mono"
 60→                />
 61→              </div>
 62→
 63→              <div className="space-y-2">
 64→                <Label htmlFor="password" className="font-bold uppercase text-sm">
 65→                  Password
 66→                </Label>
 67→                <Input
 68→                  id="password"
 69→                  type="password"
 70→                  value={password}
 71→                  onChange={(e) => setPassword(e.target.value)}
 72→                  placeholder="••••••••"
 73→                  required
 74→                  className="border-2 border-foreground h-12 font-mono"
 75→                />
 76→              </div>
 77→
 78→              <Button
 79→                type="submit"
 80→                disabled={loading}
 81→                className="w-full h-12 text-lg font-bold uppercase border-4 border-foreground shadow-brutal hover-brutal"
 82→              >
 83→                {loading ? 'LOGGING IN...' : 'LOG IN'}
 84→              </Button>
 85→            </form>
 86→
 87→            <div className="mt-8 pt-6 border-t-2 border-border text-center">
 88→              <p className="text-muted-foreground font-mono text-sm">
 89→                Don't have a team?{' '}
 90→                <Link to="/signup" className="text-foreground font-bold hover:underline">
 91→                  CREATE TEAM
 92→                </Link>
 93→              </p>
 94→            </div>
 95→          </div>
 96→        </div>
 97→      </main>
 98→    </div>
 99→  );
100→}
