  1→import { useState, useMemo } from 'react';
  2→import { LogOut, RefreshCw, Search } from 'lucide-react';
  3→import { Button } from '@/components/ui/button';
  4→import { Input } from '@/components/ui/input';
  5→import {
  6→  Select,
  7→  SelectContent,
  8→  SelectItem,
  9→  SelectTrigger,
 10→  SelectValue,
 11→} from '@/components/ui/select';
 12→import { useAdminAuth } from '@/contexts/AdminAuthContext';
 13→import { useAdminData } from '@/hooks/useAdminData';
 14→import { AdminStatsCards } from '@/components/admin/AdminStatsCards';
 15→import { TeamProgressCard } from '@/components/admin/TeamProgressCard';
 16→import { TimerControls } from '@/components/admin/TimerControls';
 17→import { DisplayControls } from '@/components/admin/DisplayControls';
 18→import type { Database } from '@/integrations/supabase/types';
 19→
 20→type SprintPhase = Database['public']['Enums']['sprint_phase'];
 21→
 22→const phaseOptions: { value: SprintPhase | 'all'; label: string }[] = [
 23→  { value: 'all', label: 'All Phases' },
 24→  { value: 'waiting', label: 'Waiting' },
 25→  { value: 'phase_1', label: 'Phase 1' },
 26→  { value: 'phase_2', label: 'Phase 2' },
 27→  { value: 'phase_3', label: 'Phase 3' },
 28→  { value: 'phase_4', label: 'Phase 4' },
 29→  { value: 'completed', label: 'Completed' },
 30→];
 31→
 32→export default function Admin() {
 33→  const { signOut, user } = useAdminAuth();
 34→  const { teams, stats, loading, error, refetch } = useAdminData();
 35→  const [searchQuery, setSearchQuery] = useState('');
 36→  const [phaseFilter, setPhaseFilter] = useState<SprintPhase | 'all'>('all');
 37→
 38→  const filteredTeams = useMemo(() => {
 39→    return teams.filter((team) => {
 40→      const matchesSearch = team.name.toLowerCase().includes(searchQuery.toLowerCase());
 41→      const matchesPhase = phaseFilter === 'all' || team.currentPhase === phaseFilter;
 42→      return matchesSearch && matchesPhase;
 43→    });
 44→  }, [teams, searchQuery, phaseFilter]);
 45→
 46→  return (
 47→    <div className="min-h-screen bg-background">
 48→      {/* Header */}
 49→      <header className="border-b-4 border-foreground">
 50→        <div className="max-w-7xl mx-auto px-4 py-4 flex items-center justify-between">
 51→          <div>
 52→            <h1 className="text-2xl font-mono font-bold tracking-tight">[HABITAT] ADMIN</h1>
 53→            <p className="text-muted-foreground font-mono text-xs">{user?.email}</p>
 54→          </div>
 55→          <div className="flex items-center gap-2">
 56→            <Button
 57→              variant="outline"
 58→              size="icon"
 59→              onClick={refetch}
 60→              disabled={loading}
 61→              className="border-2 border-foreground"
 62→            >
 63→              <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
 64→            </Button>
 65→            <Button
 66→              variant="outline"
 67→              onClick={signOut}
 68→              className="border-2 border-foreground font-mono"
 69→            >
 70→              <LogOut className="w-4 h-4 mr-2" />
 71→              Logout
 72→            </Button>
 73→          </div>
 74→        </div>
 75→      </header>
 76→
 77→      <main className="max-w-7xl mx-auto px-4 py-6 space-y-6">
 78→        {error && (
 79→          <div className="border-4 border-destructive p-4 text-destructive font-mono">
 80→            Error: {error}
 81→          </div>
 82→        )}
 83→
 84→        {/* Timer Controls */}
 85→        <TimerControls />
 86→
 87→        {/* Display Controls */}
 88→        <DisplayControls />
 89→
 90→        {/* Stats Overview */}
 91→        <AdminStatsCards stats={stats} />
 92→
 93→        {/* Teams List */}
 94→        <div className="space-y-4">
 95→          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
 96→            <h2 className="font-mono font-bold text-lg">ALL TEAMS</h2>
 97→            <span className="font-mono text-sm text-muted-foreground">
 98→              {filteredTeams.length} of {teams.length} teams
 99→            </span>
100→          </div>
101→
102→          {/* Search and Filter */}
103→          <div className="flex flex-col sm:flex-row gap-3">
104→            <div className="relative flex-1">
105→              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
106→              <Input
107→                placeholder="Search teams..."
108→                value={searchQuery}
109→                onChange={(e) => setSearchQuery(e.target.value)}
110→                className="pl-10 border-2 border-foreground font-mono"
111→              />
112→            </div>
113→            <Select value={phaseFilter} onValueChange={(value) => setPhaseFilter(value as SprintPhase | 'all')}>
114→              <SelectTrigger className="w-full sm:w-[180px] border-2 border-foreground font-mono">
115→                <SelectValue placeholder="Filter by phase" />
116→              </SelectTrigger>
117→              <SelectContent>
118→                {phaseOptions.map((option) => (
119→                  <SelectItem key={option.value} value={option.value} className="font-mono">
120→                    {option.label}
121→                  </SelectItem>
122→                ))}
123→              </SelectContent>
124→            </Select>
125→          </div>
126→
127→          {loading && teams.length === 0 ? (
128→            <div className="flex items-center justify-center p-12">
129→              <div className="w-8 h-8 border-4 border-foreground border-t-transparent rounded-full animate-spin" />
130→            </div>
131→          ) : filteredTeams.length === 0 ? (
132→            <div className="border-4 border-dashed border-muted-foreground p-12 text-center">
133→              <p className="font-mono text-muted-foreground">
134→                {teams.length === 0 ? 'No teams yet' : 'No teams match your filters'}
135→              </p>
136→            </div>
137→          ) : (
138→            <div className="space-y-3">
139→              {filteredTeams.map((team) => (
140→                <TeamProgressCard key={team.id} team={team} onTeamUpdated={refetch} />
141→              ))}
142→            </div>
143→          )}
144→        </div>
145→      </main>
146→    </div>
147→  );
148→}
