  1→import { createContext, useContext, useState, useEffect, ReactNode, useCallback } from 'react';
  2→import { supabase } from '@/integrations/supabase/client';
  3→import type { TrackType } from '@/data/trackConfig';
  4→
  5→interface Team {
  6→  id: string;
  7→  name: string;
  8→  event_id: string | null;
  9→  invite_code: string;
 10→  track: TrackType | null;
 11→}
 12→
 13→interface TeamAuthContextType {
 14→  team: Team | null;
 15→  loading: boolean;
 16→  isAuthenticated: boolean;
 17→  createTeam: (teamName: string, password: string, memberNames?: string[]) => Promise<{ error: string | null; team: Team | null }>;
 18→  loginTeam: (teamName: string, password: string) => Promise<{ error: string | null; team: Team | null }>;
 19→  logout: () => void;
 20→  setTrack: (track: TrackType) => Promise<void>;
 21→}
 22→
 23→const TeamAuthContext = createContext<TeamAuthContextType | undefined>(undefined);
 24→
 25→const TEAM_SESSION_KEY = 'habitat_team_session';
 26→
 27→async function hashPassword(password: string): Promise<string> {
 28→  const encoder = new TextEncoder();
 29→  const data = encoder.encode(password);
 30→  const hash = await crypto.subtle.digest('SHA-256', data);
 31→  return Array.from(new Uint8Array(hash))
 32→    .map(b => b.toString(16).padStart(2, '0'))
 33→    .join('');
 34→}
 35→
 36→function generateInviteCode(): string {
 37→  return Math.random().toString(36).substring(2, 8).toUpperCase();
 38→}
