  1→import { useState, useEffect, useCallback } from 'react';
  2→import { supabase } from '@/integrations/supabase/client';
  3→import type { Database } from '@/integrations/supabase/types';
  4→
  5→type SprintPhase = Database['public']['Enums']['sprint_phase'];
  6→
  7→export interface SprintTimerState {
  8→  status: 'stopped' | 'running' | 'paused';
  9→  remainingSeconds: number;
 10→  isRunning: boolean;
 11→  durationSeconds: number;
 12→  loading: boolean;
 13→  displayPhase: SprintPhase;
 14→  promoCode: string | null;
 15→  appLink: string | null;
 16→  displayImageUrl: string | null;
 17→}
 18→
 19→interface TimerRow {
 20→  id: string;
 21→  status: string;
 22→  duration_seconds: number;
 23→  started_at: string | null;
 24→  paused_at: string | null;
 25→  elapsed_before_pause: number;
 26→  updated_at: string;
 27→  display_phase: SprintPhase;
 28→  promo_code: string | null;
 29→  app_link: string | null;
 30→  display_image_url: string | null;
 31→}
 32→
 33→const TIMER_ID = '00000000-0000-0000-0000-000000000001';
 34→
 35→export function useSprintTimer() {
 36→  const [timerData, setTimerData] = useState<TimerRow | null>(null);
 37→  const [remainingSeconds, setRemainingSeconds] = useState(0);
 38→  const [loading, setLoading] = useState(true);
 39→
 40→  const calculateRemaining = useCallback((data: TimerRow): number => {
 41→    const now = Date.now();
 42→    
 43→    if (data.status === 'stopped') {
 44→      return data.duration_seconds;
 45→    }
 46→    
 47→    if (data.status === 'paused') {
 48→      if (data.started_at && data.paused_at) {
 49→        const startedAt = new Date(data.started_at).getTime();
 50→        const pausedAt = new Date(data.paused_at).getTime();
 51→        const elapsed = Math.floor((pausedAt - startedAt) / 1000) + data.elapsed_before_pause;
 52→        return Math.max(0, data.duration_seconds - elapsed);
 53→      }
 54→      return data.duration_seconds - data.elapsed_before_pause;
 55→    }
 56→    
 57→    if (data.status === 'running' && data.started_at) {
 58→      const startedAt = new Date(data.started_at).getTime();
 59→      const elapsed = Math.floor((now - startedAt) / 1000) + data.elapsed_before_pause;
 60→      return Math.max(0, data.duration_seconds - elapsed);
 61→    }
 62→    
 63→    return data.duration_seconds;
 64→  }, []);
 65→
 66→  const fetchTimer = useCallback(async () => {
 67→    const { data, error } = await supabase
 68→      .from('sprint_timer')
 69→      .select('*')
 70→      .eq('id', TIMER_ID)
 71→      .maybeSingle();
 72→    
 73→    if (error) {
 74→      console.error('Error fetching timer:', error);
 75→      setLoading(false);
 76→      return;
 77→    }
 78→    
 79→    // If no timer exists, create the default one
 80→    if (!data) {
 81→      const { data: newData, error: insertError } = await supabase
 82→        .from('sprint_timer')
 83→        .insert({
 84→          id: TIMER_ID,
 85→          status: 'stopped',
 86→          duration_seconds: 14400,
 87→          elapsed_before_pause: 0,
 88→          display_phase: 'waiting',
 89→        })
 90→        .select()
 91→        .single();
 92→      
 93→      if (insertError) {
 94→        console.error('Error creating timer:', insertError);
 95→        setLoading(false);
 96→        return;
 97→      }
 98→      
 99→      setTimerData(newData as TimerRow);
100→      setRemainingSeconds(calculateRemaining(newData as TimerRow));
101→      setLoading(false);
102→      return;
103→    }
104→    
105→    setTimerData(data as TimerRow);
106→    setRemainingSeconds(calculateRemaining(data as TimerRow));
107→    setLoading(false);
108→  }, [calculateRemaining]);
109→
110→  // Initial fetch
111→  useEffect(() => {
112→    fetchTimer();
113→  }, [fetchTimer]);
114→
115→  // Real-time subscription
116→  useEffect(() => {
117→    const channel = supabase
118→      .channel('sprint_timer_changes')
119→      .on(
120→        'postgres_changes',
121→        {
122→          event: 'UPDATE',
123→          schema: 'public',
124→          table: 'sprint_timer',
125→          filter: `id=eq.${TIMER_ID}`,
126→        },
127→        (payload) => {
128→          const newData = payload.new as TimerRow;
129→          setTimerData(newData);
130→          setRemainingSeconds(calculateRemaining(newData));
131→        }
132→      )
133→      .subscribe();
134→
135→    return () => {
136→      supabase.removeChannel(channel);
137→    };
138→  }, [calculateRemaining]);
139→
140→  // Client-side countdown when running
141→  useEffect(() => {
142→    if (!timerData || timerData.status !== 'running') return;
143→
144→    const interval = setInterval(() => {
145→      setRemainingSeconds(calculateRemaining(timerData));
146→    }, 1000);
147→
148→    return () => clearInterval(interval);
149→  }, [timerData, calculateRemaining]);
150→
151→  return {
152→    status: (timerData?.status || 'stopped') as SprintTimerState['status'],
153→    remainingSeconds,
154→    isRunning: timerData?.status === 'running',
155→    durationSeconds: timerData?.duration_seconds || 14400,
156→    loading,
157→    displayPhase: timerData?.display_phase || 'waiting',
158→    promoCode: timerData?.promo_code || null,
159→    appLink: timerData?.app_link || null,
160→    displayImageUrl: timerData?.display_image_url || null,
161→  };
162→}
