 5→
 6→const AI_COOLDOWN_MS = 10_000;
 7→
 8→export interface Phase1Data {
 9→  problem: string;
10→  solution: string;
11→  customer: string;
12→  name: string;
13→  mvpScope?: string;
14→  targetCustomer?: string;
