40→export function useAIGeneration() {
41→  const [isGenerating, setIsGenerating] = useState(false);
42→  const lastGenerationTime = useRef<number>(0);
43→
44→  const generate = async (
45→    type: GeneratorType,
46→    phase1Data: Phase1Data,
47→    segmentData?: SegmentData,
48→    searchFilters?: SearchFilters,
49→    track?: string
50→  ): Promise<string | null> => {
51→    const now = Date.now();
52→    const elapsed = now - lastGenerationTime.current;
53→    if (elapsed < AI_COOLDOWN_MS) {
54→      const waitSec = Math.ceil((AI_COOLDOWN_MS - elapsed) / 1000);
55→      toast.error(`Please wait ${waitSec}s before generating again`);
56→      return null;
57→    }
58→
59→    setIsGenerating(true);
60→    lastGenerationTime.current = now;
61→
62→    try {
63→      const { data, error } = await supabase.functions.invoke('generate-startup-content', {
64→        body: { type, phase1Data, segmentData, searchFilters, track: track || 'startup' },
65→      });
66→
67→      if (error) {
68→        console.error('AI generation error:', error);
69→        toast.error('Failed to generate content. Please try again.');
70→        return null;
71→      }
72→
73→      if (data?.error) {
74→        toast.error(data.error);
75→        return null;
76→      }
77→
78→      return data?.content || null;
79→    } catch (err) {
80→      console.error('AI generation error:', err);
81→      toast.error('Failed to generate content. Please try again.');
82→      return null;
83→    } finally {
84→      setIsGenerating(false);
85→    }
86→  };
87→
88→  return { generate, isGenerating };
89→}
