395→serve(async (req) => {
396→  if (req.method === "OPTIONS") {
397→    return new Response(null, { headers: corsHeaders });
398→  }
399→
400→  try {
401→    const { type, phase1Data, segmentData, searchFilters, track } = await req.json() as {
402→      type: GeneratorType;
403→      phase1Data: Phase1Data;
404→      segmentData?: SegmentData;
405→      searchFilters?: SearchFilters;
406→      track?: TrackType;
407→    };
408→
409→    // Rate limit by authorization token
410→    const authToken = req.headers.get("authorization") || "anonymous";
411→    const rateCheck = checkRateLimit(authToken);
412→    if (!rateCheck.allowed) {
413→      return new Response(
414→        JSON.stringify({
415→          error: `You've used all ${RATE_LIMIT_MAX} AI generations this hour. Try again in ${Math.ceil((rateCheck.retryAfterSec || 60) / 60)} minutes.`,
416→        }),
417→        { status: 429, headers: { ...corsHeaders, "Content-Type": "application/json" } }
418→      );
419→    }
420→
421→    if (!type || !phase1Data) {
422→      return new Response(
423→        JSON.stringify({ error: "Missing required fields: type and phase1Data" }),
424→        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
425→      );
426→    }
427→
428→    const GEMINI_API_KEY = Deno.env.get("GEMINI_API_KEY");
429→    if (!GEMINI_API_KEY) {
430→      console.error("GEMINI_API_KEY is not configured");
431→      return new Response(
432→        JSON.stringify({ error: "AI service not configured" }),
433→        { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
434→      );
435→    }
436→
437→    const response = await fetch("https://generativelanguage.googleapis.com/v1beta/openai/chat/completions", {
438→      method: "POST",
439→      headers: {
440→        Authorization: `Bearer ${GEMINI_API_KEY}`,
441→        "Content-Type": "application/json",
442→      },
443→      body: JSON.stringify({
444→        model: "gemini-2.0-flash",
445→        messages: [
446→          { role: "system", content: getSystemPrompt(type, track || 'startup') },
447→          { role: "user", content: getUserPrompt(type, phase1Data, segmentData, searchFilters) },
448→        ],
449→      }),
450→    });
451→
452→    if (!response.ok) {
453→      if (response.status === 429) {
454→        return new Response(
455→          JSON.stringify({ error: "Rate limit exceeded. Please try again in a moment." }),
456→          { status: 429, headers: { ...corsHeaders, "Content-Type": "application/json" } }
457→        );
458→      }
459→      if (response.status === 402) {
460→        return new Response(
461→          JSON.stringify({ error: "AI credits exhausted. Please add credits to continue." }),
462→          { status: 402, headers: { ...corsHeaders, "Content-Type": "application/json" } }
463→        );
464→      }
465→      const errorText = await response.text();
466→      console.error("AI gateway error:", response.status, errorText);
467→      return new Response(
468→        JSON.stringify({ error: "Failed to generate content" }),
469→        { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
470→      );
471→    }
472→
473→    const result = await response.json();
474→    const content = result.choices?.[0]?.message?.content;
475→
476→    if (!content) {
477→      return new Response(
478→        JSON.stringify({ error: "No content generated" }),
479→        { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
480→      );
481→    }
482→
483→    return new Response(
484→      JSON.stringify({ content }),
485→      { headers: { ...corsHeaders, "Content-Type": "application/json" } }
486→    );
487→  } catch (error) {
488→    console.error("generate-startup-content error:", error);
489→    return new Response(
490→      JSON.stringify({ error: error instanceof Error ? error.message : "Unknown error" }),
491→      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
492→    );
493→  }
494→});
