 1→import { useSprintTimer } from '@/hooks/useSprintTimer';
 2→import { cn } from '@/lib/utils';
 3→import { formatTime } from '@/lib/timerUtils';
 4→
 5→function getTimerColor(remainingSeconds: number, status: string): string {
 6→  if (status === 'stopped') return 'text-muted-foreground';
 7→  if (status === 'paused') return 'text-yellow-600';
 8→  
 9→  if (remainingSeconds <= 60) return 'text-red-600 animate-pulse';
10→  if (remainingSeconds <= 600) return 'text-red-600'; // < 10 min
11→  if (remainingSeconds <= 1800) return 'text-yellow-600'; // < 30 min
12→  return 'text-green-600';
13→}
14→
15→function getStatusBadge(status: string): { label: string; className: string } {
16→  switch (status) {
17→    case 'running':
18→      return { label: 'LIVE', className: 'bg-green-600 text-white' };
19→    case 'paused':
20→      return { label: 'PAUSED', className: 'bg-yellow-600 text-white' };
21→    default:
22→      return { label: 'READY', className: 'bg-muted text-muted-foreground' };
23→  }
24→}
25→
26→export function SprintTimer() {
27→  const { remainingSeconds, status, loading } = useSprintTimer();
28→  
29→  if (loading) {
30→    return (
31→      <div className="border-4 border-foreground p-4 flex items-center justify-center gap-4">
32→        <div className="w-6 h-6 border-4 border-foreground border-t-transparent rounded-full animate-spin" />
33→        <span className="font-mono text-sm">Loading timer...</span>
34→      </div>
35→    );
36→  }
37→
38→  const badge = getStatusBadge(status);
39→  const timerColor = getTimerColor(remainingSeconds, status);
40→
41→  return (
42→    <div className="border-4 border-foreground p-4 flex flex-col sm:flex-row items-center justify-between gap-4">
43→      <div className="flex items-center gap-3">
44→        <span className={cn('px-2 py-1 text-xs font-mono font-bold', badge.className)}>
45→          {badge.label}
46→        </span>
47→        <span className="font-mono text-sm text-muted-foreground">SPRINT TIMER</span>
48→      </div>
49→      
50→      <div className={cn('font-mono text-4xl sm:text-5xl font-bold tracking-wider', timerColor)}>
51→        {formatTime(remainingSeconds)}
52→      </div>
53→      
54→      {status === 'running' && remainingSeconds <= 1800 && (
55→        <span className="font-mono text-xs text-muted-foreground animate-pulse">
56→          {remainingSeconds <= 60 ? '⚡ FINAL MINUTE!' : remainingSeconds <= 600 ? '🔥 LESS THAN 10 MIN!' : '⏰ LESS THAN 30 MIN!'}
57→        </span>
58→      )}
59→    </div>
60→  );
61→}
